def p(g):
    g = [r[:] for r in g]
    r_gap = None
    r_solid = None
    for i in range(10):
        if g[i][2:8] == [5,5,5,0,5,5]:
            r_gap = i
        if g[i][2:8] == [5,5,5,5,5,5]:
            r_solid = i
    rotated = False
    if r_gap is None:
        g = [list(r) for r in zip(*g[::-1])]
        rotated = True
        for i in range(10):
            if g[i][2:8] == [5,5,5,0,5,5]:
                r_gap = i
            if g[i][2:8] == [5,5,5,5,5,5]:
                r_solid = i
    top = min(r_gap, r_solid)
    bot = max(r_gap, r_solid)
    for r in range(top+1, bot):
        for c in range(3, 7):
            g[r][c] = 8
    g[r_gap][5] = 8
    if r_solid < r_gap:
        for r in range(r_gap+1, 10):
            g[r][5] = 8
    else:
        for r in range(0, r_gap):
            g[r][5] = 8
    if rotated:
        g = [list(r) for r in zip(*g)][::-1]
    return g

